class Solution(object):
    def containsPattern(self, arr, m, k):
        for i in range(len(arr) - m * k + 1):
            valid = True
            for j in range(m * (k - 1)):
                if arr[i + j] != arr[i + j + m]:
                    valid = False
                    break
            if valid:
                return True
        return False
